#!/usr/bin/env node
// migrate-fa-markup.mjs — rewrite Font Awesome `<i class="fa…">` tags to
// SVG sprite references `<svg class="icon …"><use href="#fa-<name>"/></svg>`.
//
// Idempotent: once a file has no FA <i> tags, re-running is a no-op.
// Scope: source files only — never touches blog-module/blog-entries/ (those
// are regenerated by blog-processor.js) and never walks node_modules.
//
// Usage:
//   node scripts/build/migrate-fa-markup.mjs           # apply
//   node scripts/build/migrate-fa-markup.mjs --dry     # preview only

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const REPO_ROOT = path.resolve(path.dirname(__filename), '..', '..');

const SCAN_EXT = /\.(html|js)$/;
const SCAN_EXCLUDES = [
    /\/node_modules\//,
    /\/blog-module\/blog-entries\//,
    /\.min\.(js|css)$/,
    /\/scripts\/build\/migrate-fa-markup\.mjs$/,
    /\/scripts\/build\/build-icon-sprite\.mjs$/
];

function walk(dir, out = []) {
    for (const e of fs.readdirSync(dir, { withFileTypes: true })) {
        const abs = path.join(dir, e.name);
        if (SCAN_EXCLUDES.some(re => re.test(abs))) continue;
        if (e.isDirectory()) walk(abs, out);
        else if (SCAN_EXT.test(e.name)) out.push(abs);
    }
    return out;
}

// Match a FA <i> tag with no inner content. Captures class attr content and
// any post-class attributes (id, style, aria-*, data-*, role, title).
//
// Rejects tags whose class list lacks a `fa-*` token — so a stray `<i>`
// used as a text italic is left alone.
const I_TAG_RE = /<i\s+class=(["'])([^"']*?)\1([^>]*)><\/i>/g;

// Pull the first `fa-<name>` token that isn't a modifier (spin/pulse/size).
function extractIconName(classAttr) {
    const tokens = classAttr.split(/\s+/).filter(Boolean);
    for (const t of tokens) {
        const m = t.match(/^fa-([a-z][a-z0-9-]*)$/);
        if (!m) continue;
        const name = m[1];
        if (MODIFIERS.has(name)) continue;
        if (/^[0-9]x$/.test(name)) continue;
        if (/^rotate-\d+$/.test(name)) continue;
        return name;
    }
    return null;
}

// FA modifier classes we keep on the <svg> so the same styling still works.
// Everything else (fas/fab/far, fa-<name>) is dropped from the output class.
const MODIFIERS = new Set(['spin', 'pulse', 'flip', 'flip-horizontal', 'flip-vertical']);
const DROP_PREFIXES = new Set(['fas', 'fab', 'far', 'fa']);

function rewriteClass(classAttr, iconName) {
    const kept = ['icon'];
    for (const t of classAttr.split(/\s+/).filter(Boolean)) {
        if (DROP_PREFIXES.has(t)) continue;
        if (t === `fa-${iconName}`) continue;
        // Size modifiers (fa-2x etc.) — keep as-is so existing .fa-2x CSS, if
        // any, still applies. Rare in this repo.
        kept.push(t);
    }
    return kept.join(' ');
}

function migrateText(text) {
    let changes = 0;
    const result = text.replace(I_TAG_RE, (match, quote, classAttr, rest) => {
        const name = extractIconName(classAttr);
        if (!name) return match;
        const newClass = rewriteClass(classAttr, name);
        changes++;
        // `rest` captures any trailing attributes (style, id, aria-*, …);
        // we keep them on the new <svg> to preserve inline styling.
        const trailing = rest.trim() ? ` ${rest.trim()}` : '';
        const ariaHidden = /aria-hidden=/.test(rest) ? '' : ' aria-hidden="true"';
        return `<svg class="${newClass}"${ariaHidden}${trailing}><use href="#fa-${name}"/></svg>`;
    });
    return { result, changes };
}

function main() {
    const dry = process.argv.includes('--dry');
    const files = walk(REPO_ROOT);
    let totalChanges = 0;
    let touched = 0;

    for (const abs of files) {
        const original = fs.readFileSync(abs, 'utf8');
        const { result, changes } = migrateText(original);
        if (changes === 0) continue;
        touched++;
        totalChanges += changes;
        const rel = path.relative(REPO_ROOT, abs);
        console.log(`${dry ? '·' : '✓'} ${rel}  (${changes} tag${changes === 1 ? '' : 's'})`);
        if (!dry) fs.writeFileSync(abs, result, 'utf8');
    }

    console.log(
        dry
            ? `\n(dry-run) would migrate ${totalChanges} tag(s) across ${touched} file(s).`
            : `\n✓ migrated ${totalChanges} tag(s) across ${touched} file(s).`
    );
}

main();
